```typescript
'use client';

import { useState } from 'react';
import { useRouter } from 'next/navigation';
import { createClient } from '@/lib/supabase/client';
import Button from '@/components/ui/Button';
import Input from '@/components/ui/Input';
import Card from '@/components/ui/Card';
import { toast } from 'sonner';

export default function ProgramForm({ merchantId }: { merchantId: string }) {
  const router = useRouter();
  const [loading, setLoading] = useState(false);
  const [form, setForm] = useState({ name: '', type: 'stamp' as 'stamp' | 'points', target: 10, welcomeBonus: 1 });

  const update = (key: string, value: string | number) => setForm(prev => ({ ...prev, [key]: value }));

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setLoading(true);
    const supabase = createClient();

    const { error } = await supabase.from('loyalty_programs').insert({
      merchant_id: merchantId,
      name: form.name,
      type: form.type,
      target: form.target,
      welcome_bonus: form.welcomeBonus,
    });

    if (error) { toast.error(error.message); setLoading(false); return; }
    toast.success('Programme créé !');
    router.push('/merchant/programs');
    router.refresh();
  };

  return (
    <Card padding="lg" className="max-w-lg">
      <form onSubmit={handleSubmit} className="space-y-4">
        <Input label="Nom du programme" value={form.name} onChange={e => update('name', e.target.value)} required placeholder="ex: Carte Café" />

        <div className="space-y-1.5">
          <label className="text-[13px] font-medium text-[var(--text-secondary)]">Type</label>
          <div className="flex gap-3">
            {(['stamp', 'points'] as const).map(t => (
              <button key={t} type="button" onClick={() => update('type', t)}
                className={`flex-1 px-4 py-2 rounded-lg text-sm border transition-all ${
                  form.type === t
                    ? 'border-[var(--accent)] bg-[var(--accent-subtle)] text-[var(--accent-text)] font-medium'
                    : 'border-[var(--border-default)] text-[var(--text-secondary)] hover:border-[var(--border-strong)]'
                }`}
              >
                {t === 'stamp' ? 'Tampons' : 'Points'}
              </button>
            ))}
          </div>
        </div>

        <Input label={form.type === 'stamp' ? 'Tampons requis' : 'Points objectif'} type="number" min={1}
          value={String(form.target)} onChange={e => update('target', parseInt(e.target.value) || 1)} />

        <Input label="Bonus de bienvenue" type="number" min={0}
          value={String(form.welcomeBonus)} onChange={e => update('welcomeBonus', parseInt(e.target.value) || 0)} />

        <div className="flex gap-3 pt-2">
          <Button type="submit" loading={loading}>Créer le programme</Button>
          <Button variant="ghost" onClick={() => router.back()}>Annuler</Button>
        </div>
      </form>
    </Card>
  );
}
```

